    );
    assert_eq!(
        dimension(&broad_report, "policy-scope")["scoreBasisPoints"],
        0
    );
    assert_eq!(broad_report["policy"]["scopeOk"], false);
    assert_eq!(broad_report["qualityScoreBasisPoints"], 0);

